mapper.sql:
WITH RECURSIVE TASK_TREE_ALL AS ( SELECT TASK_PJT_NO , TASK_NO , TASK_JOB , TASK_PRE_NO , TASK_LEVEL , TASK_STATUS , CAST(TASK_JOB AS CHAR(1000)) AS NAVI_PATH , CAST(LPAD(TASK_SORT, 3, '0') AS CHAR(1000)) AS SORT_PATH FROM tb_project_task WHERE TASK_LEVEL = 1
AND TASK_PJT_NO = #{pjtNo}
UNION ALL SELECT T.TASK_PJT_NO , T.TASK_NO , T.TASK_JOB , T.TASK_PRE_NO , T.TASK_LEVEL , T.TASK_STATUS , CAST(CONCAT(TREE.NAVI_PATH, '>', T.TASK_JOB) AS CHAR(1000)) AS NAVI_PATH , CAST(CONCAT(TREE.SORT_PATH, LPAD(T.TASK_SORT, 3, '0')) AS CHAR(1000)) AS SORT_PATH FROM TB_PROJECT_TASK T JOIN TASK_TREE_ALL TREE ON T.TASK_PRE_NO = TREE.TASK_NO AND T.TASK_PJT_NO = TREE.TASK_PJT_NO WHERE T.TASK_LEVEL > 1 ) , TASK_TREE_LAST AS ( SELECT PI.PJT_NM , TTA.TASK_PJT_NO , TTA.TASK_NO , TTA.TASK_JOB , TTA.TASK_PRE_NO , TTA.TASK_LEVEL , TTA.NAVI_PATH , TTA.SORT_PATH , TTA.TASK_STATUS FROM TASK_TREE_ALL TTA INNER JOIN tb_project_info PI ON PI.PJT_NO = TTA.TASK_PJT_NO LEFT JOIN TB_PROJECT_TASK PT ON TTA.TASK_PJT_NO = PT.TASK_PJT_NO AND TTA.TASK_NO = PT.TASK_PRE_NO WHERE 1=1 AND PT.TASK_NO IS NULL ) , EMP_TASK AS ( SELECT PJT_NM , TTL.TASK_PJT_NO , TTL.TASK_NO , ET.EMP_NO , EI.EMP_ENM , EI.EMP_DEPT_CD , ET.EMP_TASK_STATUS , ET.EMP_TASK_STD_DT , ET.EMP_TASK_END_DT , ET.EMP_TASK_RANK FROM TASK_TREE_LAST TTL INNER JOIN tb_employee_task ET ON TTL.TASK_NO = ET.TASK_NO AND TTL.TASK_PJT_NO = ET.TASK_PJT_NO INNER JOIN tb_employee_info EI ON ET.EMP_NO = EI.EMP_NO ) , TASK_EMP AS ( SELECT PJT_NM , TASK_NO , TASK_PJT_NO , MAX(CASE WHEN EMP_DEPT_CD = 'BE' THEN EMP_ENM END) AS BACKEND , MAX(CASE WHEN EMP_DEPT_CD = 'BE' THEN EMP_TASK_STATUS END) AS BACKEND_STATUS , MAX(CASE WHEN EMP_DEPT_CD = 'BE' THEN EMP_TASK_STD_DT END) AS BACKEND_STD_DT , MAX(CASE WHEN EMP_DEPT_CD = 'BE' THEN EMP_TASK_END_DT END) AS BACKEND_END_DT , MAX(CASE WHEN EMP_DEPT_CD = 'FE' THEN EMP_ENM END) AS FRONTEND , MAX(CASE WHEN EMP_DEPT_CD = 'FE' THEN EMP_TASK_STATUS END) AS FRONTEND_STATUS , MAX(CASE WHEN EMP_DEPT_CD = 'FE' THEN EMP_TASK_STD_DT END) AS FRONTEND_STD_DT , MAX(CASE WHEN EMP_DEPT_CD = 'FE' THEN EMP_TASK_END_DT END) AS FRONTEND_END_DT FROM EMP_TASK WHERE 1=1 GROUP BY TASK_PJT_NO, TASK_NO ) , TASK_EMP_STATUS AS ( SELECT TTL.PJT_NM , TTL.TASK_NO , TTL.TASK_JOB , TTL.TASK_PRE_NO , TTL.TASK_LEVEL , TTL.NAVI_PATH , TTL.SORT_PATH , TTL.TASK_STATUS , CI01.CODE_NM , TE.BACKEND , TE.BACKEND_STATUS , CI02.CODE_NM AS BACKEND_STATUS_NM , TE.BACKEND_STD_DT , TE.BACKEND_END_DT , TE.FRONTEND , TE.FRONTEND_STATUS , CI03.CODE_NM AS FRONTEND_STATUS_NM , TE.FRONTEND_STD_DT , TE.FRONTEND_END_DT FROM TASK_TREE_LAST TTL INNER JOIN TASK_EMP TE ON TTL.TASK_PJT_NO = TE.TASK_PJT_NO AND TTL.TASK_NO = TE.TASK_NO LEFT OUTER JOIN TB_CODE_INFO CI01 ON CI01.CODE_PRE_NO = 1 AND TTL.TASK_STATUS = CI01.CODE_VALUE LEFT OUTER JOIN TB_CODE_INFO CI02 ON CI02.CODE_PRE_NO = 5 AND TE.BACKEND_STATUS = CI02.CODE_VALUE LEFT OUTER JOIN TB_CODE_INFO CI03 ON CI03.CODE_PRE_NO = 5 AND TE.FRONTEND_STATUS = CI03.CODE_VALUE )
